class Scripts {
    String build;
    String prepublishOnly;

    Scripts({
        required this.build,
        required this.prepublishOnly,
    });

    factory Scripts.fromJson(Map<String, dynamic> json) => Scripts(
        build: json["build"],
        prepublishOnly: json["prepublishOnly"],
